1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const survives = (alive: boolean, neighbors: number): boolean =>
12	  neighbors === 3 || (alive && neighbors === 2);
13	
14	const neighborsOf = ([x, y]: Cell): Cell[] =>
15	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
16	
17	export function nextGeneration(cells: Cell[]): Cell[] {
18	  const liveSet = new Set(cells.map(cellKey));
19	  const candidates = new Map<string, Cell>();
20	  const counts = new Map<string, number>();
21	
22	  for (const cell of cells) {
23	    for (const neighbor of neighborsOf(cell)) {
24	      const key = cellKey(neighbor);
25	      candidates.set(key, neighbor);
26	      counts.set(key, (counts.get(key) ?? 0) + 1);
27	    }
28	  }
29	
30	  return [...candidates]
31	    .filter(([key, _]) => survives(liveSet.has(key), counts.get(key)!))
32	    .map(([, cell]) => cell);
33	}
34

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return empty array when given empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a block (2x2) unchanged as still life", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result.sort()).toEqual(block.sort());
18	  });
19	  it("should oscillate a vertical blinker to horizontal", () => {
20	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
21	    const horizontal: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
22	    const result = nextGeneration(vertical);
23	    expect(result.sort()).toEqual(horizontal.sort());
24	  });
25	  it("should kill a live cell with 4 neighbors (overpopulation)", () => {
26	    // Center cell (1,1) has 4 diagonal neighbors → dies
27	    const input: [number, number][] = [
28	      [0, 0], [1, 0], [2, 0],
29	      [1, 1],
30	      [0, 2], [1, 2], [2, 2],
31	    ];
32	    const result = nextGeneration(input);
33	    expect(result).not.toContainEqual([1, 1]);
34	  });
35	  it("should birth a dead cell with exactly 3 live neighbors (reproduction)", () => {
36	    // Dead cell (1,1) has 3 live neighbors → becomes alive
37	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1]];
38	    const result = nextGeneration(input);
39	    expect(result).toContainEqual([1, 1]);
40	  });
41	  it("should handle negative coordinates correctly", () => {
42	    // Vertical blinker at negative coordinates oscillates to horizontal
43	    const vertical: [number, number][] = [[-5, -5], [-5, -4], [-5, -3]];
44	    const horizontal: [number, number][] = [[-6, -4], [-5, -4], [-4, -4]];
45	    const result = nextGeneration(vertical);
46	    expect(result.sort()).toEqual(horizontal.sort());
47	  });
48	});
